vector<pll> g[N], ng[N];
int s[N], ind[N], id[N];
ll dis[N];
vector<int> p[N];
int find(int x) {
    if (x == s[x])return x;
    return s[x] = find(s[x]);
}
struct node {
    ll id, d;
    bool operator<(const node& a)const {
        return a.d < d;
    }
};
void solve(int CASE)
{
    int n, R, P, S; cin >> n >> R >> P >> S;
    fa(i, 1, n)dis[i] = LNF;
    fa(i, 1, R) {
        ll u, v, w; cin >> u >> v >> w;
        g[u].pb({ v,w }), g[v].pb({ u,w });
    }

    // 并查集
    fa(i, 1, n)s[i] = i;
    fa(i, 1, n) {
        for (var& [to, w] : g[i]) {
            int e1 = find(i);
            int e2 = find(to);
            if (e1 != e2)s[e2] = e1;
        }
    }

    // 并查集后，s 离散化到 id
    var b = vector<int>();
    fa(i, 1, n)b.pb(find(i));
    sort(all(b));
    b.erase(unique(all(b)), b.end());
    var findb = [&](int value)->int {
        return upper_bound(all(b), value) - b.begin();
        };
    int m = b.size();
    fa(i, 1, n)id[i] = findb(find(i));
    fa(i, 1, n)p[id[i]].pb(i);

    // 输入单向边，更新入度
    fa(i, 1, P) {
        ll u, v, w; cin >> u >> v >> w;
        ng[u].pb({ v,w });
        ind[id[v]]++;
    }

    // 拓扑 + 多源最短路
    var in = Vec2<pll>(m + 1);     // 有哪些点到 i 集里，距离为多少 
    var flag = vector<int>(m + 1); // 拓扑排序到 i 时，是否从 S 出发
    var Q = queue<int>();          // 当前在 i 集，是否从 S 出发
    fa(i, 1, m) if (!ind[i]) {
        for (int x : p[i])in[i].pb({ x, 0 });
        flag[i] = id[S] == i;
        Q.push(i);
    }

    while (Q.size()) {
        int now = Q.front();
        Q.pop();

        // 跑多源最短路，如果 S 在这个连通块内，跑单源
        if (flag[now]) {
            var Q = priority_queue<node>();
            if (id[S] == now)Q.push({ S,0 }), dis[S] = 0; // S 单源
            else for (const var& [x, d] : in[now])        // 到 tos 集的点们 多源
                Q.push({ x,d }), dis[x] = min(d, dis[x]);

            while (Q.size()) {
                var[now, d] = Q.top();
                Q.pop();
                if (d > dis[now])continue;
                for (const var& [to, w] : g[now]) {
                    if (dis[to] > d + w) {
                        dis[to] = d + w;
                        Q.push({ to, dis[to] });
                    }
                }
            }
        }

        for (int x : p[now])
            for (const var& [to, w] : ng[x]) {
                int tos = id[to];
                ll d = dis[x] + w;
                in[tos].pb({ to, d });                 // 更新哪些点到了 tos 集中
                flag[tos] |= id[S] == tos | flag[now]; // 更新是否从 S 出发

                ind[tos]--;
                if (ind[tos] == 0)Q.push(tos);
            }
    }

    fa(i, 1, n)
        if (dis[i] == LNF)cout << "NO PATH" << endl;
        else cout << dis[i] << endl;
    return;
}
